{"code": "import json

# Read CRM 2017 data
crm_file = 'file_storage/functions.query_db:76.json'
with open(crm_file, 'r') as f:
    crm_data = json.load(f)

# Count up vs down days for CRM
crm_up_days = 0
crm_down_days = 0
for day in crm_data:
    open_price = float(day['Open'])
    close_price = float(day['Close'])
    if close_price > open_price:
        crm_up_days += 1
    elif close_price < open_price:
        crm_down_days += 1

# Read NYSE non-ETF symbols
nyse_file = 'file_storage/functions.query_db:74.json'
with open(nyse_file, 'r') as f:
    nyse_stocks = json.load(f)

company_map = {stock['Symbol']: stock['Company Description'] for stock in nyse_stocks}

print('__RESULT__:')
print(json.dumps({
    'CRM': {
        'symbol': 'CRM',
        'up': crm_up_days,
        'down': crm_down_days,
        'diff': crm_up_days - crm_down_days,
        'company': company_map['CRM']
    }
}))"}
